Еве го кодот C++ за прикажување на празен квадрат со произволна големина:
```
#include <iostream>

користејќи именски простор std;

int main() {
   int големина;
   cout << "Внесете ја големината на квадратот: ";
   cin >> големина;

   за (int i = 1; i <= големина; i++) {
       за (int j = 1; j <= големина; j++) {
           ако (i == 1 || i == големина || j == 1 || j == големина) {
